// Alle Items aus dem Input holen
const items = $input.all();

// --- 1) Draft-Item (mit draftId) finden ---
const draftItem = items.find(i => i.json.draftId);
if (!draftItem) throw new Error("Draft-Item (mit draftId) nicht gefunden.");

// --- 2) Binary-Item (mit merged.pdf) finden ---
const binaryItem = items.find(i => i.binary && Object.keys(i.binary).length > 0);
if (!binaryItem) throw new Error("Binary-Item mit PDF nicht gefunden.");

// Neue Struktur für das Output-Item aufbauen
const output = {
  json: {
    ...draftItem.json,
    ...binaryItem.json, // falls z. B. status, filesize etc. benötigt werden
  },
  binary: {
    ...binaryItem.binary, // enthält z. B. merged.pdf + metadata
  }
};

// Ein einziges Item zurückgeben
return [output];

